#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>

char* read_config_file(const char* filename) {
    struct stat sb;
    if (stat(filename, &sb) == -1) {
        return NULL;
    }

    char* config_data = malloc(sb.st_size + 1);
    if (config_data == NULL) {
        return NULL;
    }

    FILE* fp = fopen(filename, "r");
    if (fp == NULL) {
        free(config_data);
        return NULL;
    }

    size_t bytes_read = fread(config_data, 1, sb.st_size, fp);
    if (bytes_read != sb.st_size) {
        fclose(fp);
        free(config_data);
        return NULL;
    }

    config_data[sb.st_size] = '\0';
    fclose(fp);

    return config_data;
}
